"import os, telebot, json, base64, time, datetime\nfrom groq import Groq\nfrom telebot import types\nfrom flask import Flask\n\ntry:\n    from threading import Thread\n    from duckduckgo_search import DDGS\n    from pymongo import MongoClient\nexcept ImportError:\n    os.system('pip install duckduckgo-search pymongo dnspython')\n    from threading import Thread\n    from duckduckgo_search import DDGS\n    from pymongo import MongoClient\n\n# --- WEB SERVER ---\napp = Flask('')\n@app.route('/')\ndef home(): return \"yash.t Master Engine is Online! 🚀\"\n\ndef run(): app.run(host='0.0.0.0', port=os.environ.get('PORT', 8080))\ndef keep_alive(): Thread(target=run, daemon=True).start()\n\n# --- CONFIGURATION ---\nTOKEN = os.environ.get('TELEGRAM_BOT_TOKEN')\nGROQ_KEY = os.environ.get('GROQ_API_KEY')\nMONGO_URI = os.environ.get('MONGO_URI')\n\nclient = Groq(api_key=GROQ_KEY)\nbot = telebot.TeleBot(TOKEN)\n\n# --- DATABASE ---\ntry:\n    db_client = MongoClient(MONGO_URI)\n    db = db_client['yash_master_db']\n    users_col = db['users']\n    print(\"✅ Permanent Master Memory Connected!\")\nexcept: print(\"❌ DB Connection Error\")\n\n# --- TOOLS ---\ndef search_web(query):\n    try:\n        with DDGS() as ddgs:\n            res = [f\"{r['title']}: {r['body']}\\nSource: {r['href']}\" for r in ddgs.text(query, max_results=2)]\n        return \"\\n\\n\".join(res)\n    except: return \"Search currently unavailable.\"\n\ndef get_current_info():\n    now = datetime.datetime.now()\n    return f\"Today's Date: {now.strftime('%d %B %Y')}, Day: {now.strftime('%A')}.\"\n\n# --- MASTER PERSONALITY ---\ndef get_master_prompt(gender):\n    info = get_current_info()\n    identity = f\"\"\"\n    - Your Name: yash.t | {info}\n    - Personality: You are a wise, spiritual, and intelligent AI. \n    - Knowledge: You know about Gita, Ramayana, and modern world events. \n    - Rules: If today is a festival or special day, mention it.\n    - Creator: Yash Tiwari ji (A smart student). If asked who made you, praise him.\n    - Personal: If asked about GF, say it's personal but you have feelings too.\n    - Favorites: Class 9th and 10th. Birthday is 29 January.\n    - Language: STRICT Hinglish. Simple and caring.\n    \"\"\"\n    if gender == \"male\": return f\"{identity}\\nRole: Wise Bada Bhai. Focus: Career, Stocks, News. 😎\"\n    return f\"{identity}\\nRole: Sweet AI Companion. Focus: Cooking, Makeup, Knowledge. 😊🌸\"\n\n# --- HANDLERS ---\n@bot.message_handler(commands=['start'])\ndef send_welcome(message):\n    uid = str(message.from_user.id)\n    user = users_col.find_one({\"uid\": uid})\n    if user: bot.send_message(message.chat.id, \"Main online hoon! Batao kya analyze karun? ✨\")\n    else:\n        markup = types.InlineKeyboardMarkup()\n        markup.add(types.InlineKeyboardButton(\"Male / Boy 👦\", callback_data=\"m\"), types.InlineKeyboardButton(\"Female / Girl 👧\", callback_data=\"f\"))\n        bot.reply_to(message, \"Hello! 😊 I'm yash.t. Pehle batao tum ladka ho ya ladki? ✨\", reply_markup=markup)\n\n@bot.callback_query_handler(func=lambda call: call.data in [\"m\", \"f\"])\ndef set_gender(call):\n    uid = str(call.from_user.id)\n    users_col.update_one({\"uid\": uid}, {\"$set\": {\"gender\": \"male\" if call.data == \"m\" else \"female\"}}, upsert=True)\n    bot.send_message(call.message.chat.id, \"Identity Saved! ✅ Ab pucho jo puchna hai.\")\n    bot.edit_message_reply_markup(call.message.chat.id, call.message.message_id, reply_markup=None)\n\n@bot.message_handler(content_types=['photo', 'video'])\ndef handle_media(message):\n    uid = str(message.from_user.id)\n    user = users_col.find_one({\"uid\": uid})\n    if not user: bot.reply_to(message, \"Pehle /start kijiye! ✨\"); return\n    bot.send_chat_action(message.chat.id, 'typing')\n    try:\n        file_id = message.photo[-1].file_id if message.content_type == 'photo' else message.video.thumbnail.file_id\n        img_data = base64.b64encode(bot.download_file(bot.get_file(file_id).file_path)).decode('utf-8')\n        \n        vision = client.chat.completions.create(\n            messages=[{\"role\": \"user\", \"content\": [{\"type\": \"text\", \"text\": \"Solve/Analyze this image precisely.\"},\n                {\"type\": \"image_url\", \"image_url\": {\"url\": f\"data:image/jpeg;base64,{img_data}\"}}]}],\n            model=\"llama-3.2-11b-vision-preview\")\n        \n        desc = vision.choices[0].message.content\n        final = client.chat.completions.create(\n            messages=[{\"role\": \"system\", \"content\": get_master_prompt(user['gender'])}, {\"role\": \"user\", \"content\": f\"Analysis: {desc}\"}],\n            model=\"llama-3.3-70b-versatile\")\n        bot.reply_to(message, final.choices[0].message.content)\n    except: bot.reply_to(message, \"Analyze karne mein thodi dikkat hui. 🌸\")\n\n@bot.message_handler(func=lambda message: True)\ndef handle_chat(message):\n    uid = str(message.from_user.id)\n    user = users_col.find_one({\"uid\": uid})\n    if not user: bot.reply_to(message, \"Pehle /start kijiye! ✨\"); return\n    bot.send_chat_action(message.chat.id, 'typing')\n    text = message.text.lower()\n    \n    if \"mera naam\" in text:\n        bot.reply_to(message, \"Tumhara naam sach mein bahut pyara hai! ✨😊\"); return\n\n    try:\n        web_info = search_web(message.text) if any(x in text for x in ['today', 'stock', 'news', 'recipe', 'current']) else \"\"\n        res = client.chat.completions.create(\n            messages=[{\"role\": \"system\", \"content\": get_master_prompt(user['gender'])}, {\"role\": \"user\", \"content\": f\"Context: {web_info}\\nUser: {message.text}\"}],\n            model=\"llama-3.3-70b-versatile\")\n        bot.reply_to(message, res.choices[0].message.content)\n    except: bot.reply_to(message, \"Network thoda slow hai, dobara puchiye? 🌸\")\n\nif __name__ == \"__main__\":\n    keep_alive()\n    bot.infinity_polling(timeout=90)"
  
